import re

# Get the results from previous queries
quote_result = locals().get('var_functions.query_db:5')
quotelineitems_result = locals().get('var_functions.query_db:8')

# Parse JSON if results are strings
if isinstance(quote_result, str):
    with open(quote_result, 'r') as f:
        quote_result = json.load(f)
if isinstance(quotelineitems_result, str):
    with open(quotelineitems_result, 'r') as f:
        quotelineitems_result = json.load(f)

# Clean data from corruption (remove leading # and trailing whitespace)
def clean_id(id):
    if not id:
        return id
    if isinstance(id, str):
        if id.startswith('#'):
            id = id[1:]
        return id.strip()
    return id

# Clean the QuoteLineItem records
cleaned_lineitems = []
for item in quotelineitems_result:
    cleaned_item = {}
    for field, value in item.items():
        if field.endswith('Id'):
            cleaned_item[field] = clean_id(value)
        else:
            cleaned_item[field] = value.strip() if isinstance(value, str) else value
    cleaned_lineitems.append(cleaned_item)

# Load the Quote result
cleaned_quote = {}
if quote_result and len(quote_result) > 0:
    quote = quote_result[0]
    for field, value in quote.items():
        if field.endswith('Id'):
            cleaned_quote[field] = clean_id(value)
        else:
            cleaned_quote[field] = value.strip() if isinstance(value, str) else value

print('__RESULT__:')
print(json.dumps({
    'quote': cleaned_quote,
    'line_items': cleaned_lineitems
}, indent=2))"}

{"code": "import json
import re

# Get the knowledge articles result
kb_result = locals().get('var_functions.query_db:10')

# Parse JSON if result is a string
if isinstance(kb_result, str):
    with open(kb_result, 'r') as f:
        kb_result = json.load(f)

# Search for articles about discount limits, maximum discounts, or discount policies
discount_keywords = ['discount limit', 'maximum discount', 'discount policy', 'discount approval', 'discount threshold', 'discount rules']
quantity_keywords = ['quantity limit', 'maximum quantity', 'bulk order', 'large quantity']

relevant_articles = []

for article in kb_result:
    title = article.get('title', '').lower()
    faq = article.get('faq_answer__c', '').lower()
    summary = article.get('summary', '').lower()

    text_to_search = title + ' ' + faq + ' ' + summary

    # Check for discount-related articles
    for keyword in discount_keywords:
        if keyword in text_to_search:
            relevant_articles.append(article)
            break

    # Check for quantity-related articles
    if not any(article['id'] == a['id'] for a in relevant_articles):
        for keyword in quantity_keywords:
            if keyword in text_to_search:
                relevant_articles.append(article)
                break

# Also extract the Volume-Based Discounts article specifically
volume_discount_article = None
for article in kb_result:
    if 'volume-based discounts' in article.get('title', '').lower():
        volume_discount_article = article
        break

print('__RESULT__:')
print(json.dumps({
    'relevant_articles': relevant_articles[:10],  # Limit to first 10
    'volume_discount_article': volume_discount_article
}, indent=2))"}

